generated_oml:
// Physical Components
instance PermanentMagnetSynchronousMotor : DTDFVocab:Component [
    base:desc "Permanent‑magnet synchronous motor driving the first axis of the MABI MAX 0100 robot."
]
instance GearTransmission : DTDFVocab:Component [
    base:desc "Intermediate gear transmission between the motor and the cycloidal gearbox."
]
instance CycloidalGearbox : DTDFVocab:Component [
    base:desc "Cycloidal gearbox that reduces the motor speed to the joint’s required range."
]
instance MabiMax0100FirstAxisJoint : DTDFVocab:Component [
    base:desc "First motorized revolution joint of the six‑axis MABI MAX 0100 industrial robot."
]

// Physical Sensing Components
instance MotorSideEncoder : DTDFVocab:SensingComponent [
    base:desc "Rotary encoder on the synchronous motor shaft providing angular position."
    DTDFVocab:producedData MotorSideEncoderPosition
]
instance GearboxSideEncoder : DTDFVocab:SensingComponent [
    base:desc "Rotary encoder on the gearbox output shaft providing angular position."
    DTDFVocab:producedData GearboxSideEncoderPosition
]
instance MotorCurrentSensor : DTDFVocab:SensingComponent [
    base:desc "Current sensor measuring the motor phase current (I_M) as electrical input."
    DTDFVocab:producedData MotorCurrentValue
]

// Data Transmitted (raw sensor streams)
instance MotorSideEncoderPosition : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorSideEncoder
]
instance GearboxSideEncoderPosition : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom GearboxSideEncoder
]
instance MotorCurrentValue : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorCurrentSensor
]

// Processed Data (derived traces)
instance MotorCurrentData : DTDFVocab:Data [
    base:desc "Processed data trace of the motor current I_M."
    DTDFVocab:fromData MotorCurrentValue
    DTDFVocab:inputTo SimulinkExecutionEnabler
]
instance MotorAngleData : DTDFVocab:Data [
    base:desc "Processed data trace of the motor shaft angular position."
    DTDFVocab:fromData MotorSideEncoderPosition
    DTDFVocab:inputTo SimulinkExecutionEnabler
]
instance GearboxAngleData : DTDFVocab:Data [
    base:desc "Processed data trace of the gearbox output angular position."
    DTDFVocab:fromData GearboxSideEncoderPosition
    DTDFVocab:inputTo SimulinkExecutionEnabler
]
instance TorqueData : DTDFVocab:Data [
    base:desc "Derived torque (τ) computed from motor current and system dynamics."
    DTDFVocab:fromData MotorCurrentValue
    DTDFVocab:inputTo SimulinkExecutionEnabler
]
instance AngularVelocityData : DTDFVocab:Data [
    base:desc "Derived angular velocity (ω) calculated from motor shaft angular position."
    DTDFVocab:fromData MotorAngleData
    DTDFVocab:inputTo SimulinkExecutionEnabler
]
instance AccelerationData : DTDFVocab:Data [
    base:desc "Derived angular acceleration (α) calculated from angular velocity."
    DTDFVocab:fromData AngularVelocityData
    DTDFVocab:inputTo SimulinkExecutionEnabler
]

// Acting Component
instance RobotProcessingComponent : DTDFVocab:ActingComponent [
    base:desc "Digital shadow processing engine performing real‑time friction identification and parameter inference."
]

// Enablers
instance SysMLModelingEnabler : DTDFVocab:Enabler [
    base:desc "SysML for MBSE providing structural and behavioral asset models."
    DTDFVocab:enables FrictionIdentificationService
]
instance SimulinkExecutionEnabler : DTDFVocab:Enabler [
    base:desc "Simulink executable simulation engine for analytical and data‑driven friction models."
    DTDFVocab:enables FrictionIdentificationService, FrictionModelParameterUpdateService
]
instance AssetAdministrationShellEnabler : DTDFVocab:Enabler [
    base:desc "Asset Administration Shell (AAS) linking physical asset metadata to virtual models."
    DTDFVocab:enables DataTraceLinkingService
]
instance MqttBrokerEnabler : DTDFVocab:Enabler [
    base:desc "MQTT broker that streams live sensor data to the digital twin."
    DTDFVocab:enables VisualizationDashboardService, FrictionIdentificationService, DataTraceLinkingService
]
instance DashboardUiEnabler : DTDFVocab:Enabler [
    base:desc "Dashboard UI that visualizes real‑time sensor data and simulation results."
    DTDFVocab:enables VisualizationDashboardService
]
instance DsrmEnabler : DTDFVocab:Enabler [
    base:desc "Digital Shadow Reference Model (DSRM) structuring component linking data and models."
    DTDFVocab:enables FrictionIdentificationService, DataTraceLinkingService
]

// Services
instance VisualizationDashboardService : DTDFVocab:Service [
    base:desc "Service presenting live sensor streams and simulation outputs on a user dashboard."
    DTDFVocab:provides RealTimeDataVisualizationInsight
]
instance FrictionIdentificationService : DTDFVocab:Service [
    base:desc "Continuous multi‑physics friction identification service combining white‑box and black‑box models."
    DTDFVocab:provides UpdatedFrictionModelParametersInsight, WearTemperatureEffectsInsight,
                 ControlLawAdjustmentRecommendationInsight, PotentialHardwareModificationInsight
]
instance DataTraceLinkingService : DTDFVocab:Service [
    base:desc "Automated linking of live sensor data traces to engineering models via the Asset Administration Shell."
    DTDFVocab:provides DataTraceToModelLinkageInsight
]
instance FrictionModelParameterUpdateService : DTDFVocab:Service [
    base:desc "Service enabling real‑time updating of friction model parameters during operation."
    DTDFVocab:provides FrictionModelParameterUpdateAction
]

// Insights
instance UpdatedFrictionModelParametersInsight : DTDFVocab:Insight [
    base:desc "Insights on updated friction model parameters inferred from live data."
]
instance WearTemperatureEffectsInsight : DTDFVocab:Insight [
    base:desc "Insights identifying wear or temperature effects impacting friction."
]
instance ControlLawAdjustmentRecommendationInsight : DTDFVocab:Insight [
    base:desc "Insights recommending adjustments to control‑law parameters."
]
instance PotentialHardwareModificationInsight : DTDFVocab:Insight [
    base:desc "Insights suggesting potential hardware modifications to improve performance."
]
instance RealTimeDataVisualizationInsight : DTDFVocab:Insight [
    base:desc "Insight visualizing real‑time sensor data and simulation results."
]
instance DataTraceToModelLinkageInsight : DTDFVocab:Insight [
    base:desc "Insight confirming linkages between data traces and engineering models."
]

// Action
instance FrictionModelParameterUpdateAction : DTDFVocab:Action [
    base:desc "Automatic action to update friction model parameters during operation."
    DTDFVocab:IsAutomatic true
]

instance twinning_time_scale : DTDFVocab:TimeScale [
    base:desc "Real‑time data acquisition and processing at the robot encoder rate (typically in the kHz range); continuous model identification and dashboard updates performed on the fly as the robot operates."
]

instance dt_constellation : DTDFVocab:Constellation [
    base:desc "A constellation consisting of the physical asset (MABI robot), the AAS to host contextual data, the Processing component that consumes sensor data and runs Simulink models, the Digital Shadow repository storing data traces, and the dashboard presentation layer—all interconnected via MQTT and AAS interfaces."
]

instance life_cycle_stages : DTDFVocab:EvolutionStage [
    base:desc "The digital twin encompasses the designed (ideal simulation) phase, the manufactured (physical robot) phase, and the operated phase where live data is streamed and friction models are updated in real time."
]

instance fidelity_and_validity_considerations : DTDFVocab:FidelityConsideration [
    base:desc "Trust in model fidelity through traceability of data traces to their generating processing components and models; continuous validation by comparing sensor‑derived torque and velocity against simulation outputs; use of both white‑box analytical equations and data‑driven black‑box models to account for wear, temperature, and load variations; uncertainty quantified by observing deviations between simulated and measured traces."
]

instance dt_technical_connection : DTDFVocab:TechnicalConnection [
    base:desc "Sensor data is transmitted from the robot to the digital twin via MQTT. The Asset Administration Shell exposes metadata through a REST‑like interface, while the Processing component communicates with Simulink via Simulink Coder interfaces."
]

instance standardization : DTDFVocab:Standardization [
    base:desc "Use of SysML for MBSE, Simulink for executable simulation, MQTT for IoT data streaming, and the Asset Administration Shell (AAS) as per ISO/IEC 42010 or similar standard frameworks."
]
